class UnionFind {
    constructor(size) {
        this.parent = new Array(size);
        this.rank = new Array(size).fill(0);
        for (let i = 0; i < size; i++) {
            this.parent[i] = i;
        }
    }

    find(u) {
        if (this.parent[u] !== u) {
            this.parent[u] = this.find(this.parent[u]);
        }
        return this.parent[u];
    }

    union(u, v) {
        const rootU = this.find(u);
        const rootV = this.find(v);
        if (rootU === rootV) return false;

        if (this.rank[rootU] > this.rank[rootV]) {
            this.parent[rootV] = rootU;
        } else if (this.rank[rootU] < this.rank[rootV]) {
            this.parent[rootU] = rootV;
        } else {
            this.parent[rootV] = rootU;
            this.rank[rootU]++;
        }
        return true;
    }

    countComponents() {
        const roots = new Set();
        for (let i = 0; i < this.parent.length; i++) {
            roots.add(this.find(i));
        }
        return roots.size;
    }
}

function solve(n, edges, k) {
    edges.sort((a, b) => a[2] - b[2]);
    const uf = new UnionFind(n);
    let left = 0;
    let right = edges.length > 0 ? edges[edges.length - 1][2] : 0;
    let answer = 0;

    // Check if initial components already >= k
    const initialUF = new UnionFind(n);
    for (const [u, v, time] of edges) {
        initialUF.union(u, v);
    }
    if (initialUF.countComponents() >= k) {
        return 0;
    }

    while (left <= right) {
        const mid = Math.floor((left + right) / 2);
        const tempUF = new UnionFind(n);
        for (const [u, v, time] of edges) {
            if (time > mid) {
                tempUF.union(u, v);
            }
        }
        if (tempUF.countComponents() >= k) {
            answer = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    return answer;
}

