import sys
from typing import List

class UnionFind:
    def __init__(self, size: int):
        self.parent = list(range(size))
        self.rank = [0] * size

    def find(self, u: int) -> int:
        if self.parent[u] != u:
            self.parent[u] = self.find(self.parent[u])
        return self.parent[u]

    def union(self, u: int, v: int) -> bool:
        root_u = self.find(u)
        root_v = self.find(v)
        if root_u == root_v:
            return False

        if self.rank[root_u] > self.rank[root_v]:
            self.parent[root_v] = root_u
        elif self.rank[root_u] < self.rank[root_v]:
            self.parent[root_u] = root_v
        else:
            self.parent[root_v] = root_u
            self.rank[root_u] += 1
        return True

    def count_components(self) -> int:
        roots = set()
        for i in range(len(self.parent)):
            roots.add(self.find(i))
        return len(roots)

def solve(n: int, edges: List[List[int]], k: int) -> int:
    edges.sort(key=lambda x: x[2])
    left = 0
    right = edges[-1][2] if edges else 0
    answer = 0

    # Check initial components
    initial_uf = UnionFind(n)
    for u, v, time in edges:
        initial_uf.union(u, v)
    if initial_uf.count_components() >= k:
        return 0

    # Binary search for minimal t
    while left <= right:
        mid = (left + right) // 2
        temp_uf = UnionFind(n)
        for u, v, time in edges:
            if time > mid:
                temp_uf.union(u, v)
        if temp_uf.count_components() >= k:
            answer = mid
            right = mid - 1
        else:
            left = mid + 1

    return answer
